#include<bits/stdc++.h>
using namespace std;
int fail[1000010],son[1000010][31],cnt[1000010],tot;
void insert(string s)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    cnt[p]++;
}
void getfail()
{
    queue<int> q;
    for(int i=0;i<26;i++)
    {
        if(son[0][i])
        {
            fail[son[0][i]]=0;
            q.push(son[0][i]);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=0;i<26;i++)
        {
            if(son[t][i])
            {
                fail[son[t][i]]=son[fail[t]][i];
                q.push(son[t][i]);
            }
            else
            {
                son[t][i]=son[fail[t]][i];
            }
        }
    }
}
int query(string s)
{
    int len=s.size();
    int p=0,ans=0;
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        p=son[p][x];
        for(int t=p;t!=0&&cnt[t]!=-1;t=fail[t])
        {
            ans+=cnt[t];
            cnt[t]=-1;
        }
    }
    return ans;
}
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        insert(s);
    }
    string str;
    cin>>str;
    getfail();
    printf("%d",query(str));
    return 0;
}
